"""Injecta — Web Dashboard & REST API with File IO, NoSQL, GraphQL support"""
import json
import threading
import time
import uuid
from http.server import HTTPServer, BaseHTTPRequestHandler
from typing import Any, Dict, Optional
from urllib.parse import urlparse, parse_qs


class VoidAPIHandler(BaseHTTPRequestHandler):
    engine_ref = None
    config_ref = None
    logger_ref = None
    scan_results = {}
    scan_status = "idle"
    scan_history = []

    def _json_response(self, data: dict, status: int = 200):
        self.send_response(status)
        self.send_header("Content-Type", "application/json")
        self.send_header("Access-Control-Allow-Origin", "*")
        self.end_headers()
        self.wfile.write(json.dumps(data, indent=2).encode("utf-8"))

    def _serve_html(self):
        self.send_response(200)
        self.send_header("Content-Type", "text/html; charset=utf-8")
        self.end_headers()
        self.wfile.write(DASHBOARD_HTML.encode("utf-8"))

    def log_message(self, format, *args):
        if self.logger_ref and self.logger_ref.verbose >= 2:
            self.logger_ref.debug2(f"[WEB] {args[0]} {args[1]} {args[2]}")

    def do_GET(self):
        parsed = urlparse(self.path)
        path = parsed.path.rstrip("/")
        params = parse_qs(parsed.query)
        if path == "/api/status":
            self._json_response({"status": self.scan_status, "results": self.scan_results})
        elif path == "/api/scan":
            target = params.get("target", [""])[0]
            if target:
                threading.Thread(target=self._run_scan, args=(target,), daemon=True).start()
                self._json_response({"status": "started", "target": target})
            else:
                self._json_response({"error": "No target provided"}, 400)
        elif path == "/api/history":
            self._json_response({"history": self.scan_history[-20:]})
        elif path == "/api/logs":
            since = int(params.get("since", ["0"])[0])
            logger = self.__class__.logger_ref
            if logger:
                self._json_response(logger.get_logs_since(since))
            else:
                self._json_response({"logs": [], "total": 0})
        elif path in ("/", ""):
            self._serve_html()
        else:
            self._json_response({"error": "not found"}, 404)

    def do_POST(self):
        content_length = int(self.headers.get("Content-Length", 0))
        body = self.rfile.read(content_length).decode("utf-8") if content_length else "{}"
        try:
            data = json.loads(body)
        except json.JSONDecodeError:
            data = {}
        parsed = urlparse(self.path)
        path = parsed.path.rstrip("/")
        if path == "/api/scan":
            target = data.get("target", "")
            if target:
                threading.Thread(target=self._run_scan, args=(target,), daemon=True).start()
                self._json_response({"status": "started", "target": target, "scan_id": str(uuid.uuid4())[:8]})
            else:
                self._json_response({"error": "No target provided"}, 400)
        elif path == "/api/config":
            if self.config_ref:
                self._json_response(vars(self.config_ref))
            else:
                self._json_response({"error": "no config"}, 400)
        elif path == "/api/file-read":
            target = data.get("target", "")
            path_f = data.get("path", "")
            if target and path_f:
                threading.Thread(target=self._run_file_read, args=(target, path_f), daemon=True).start()
                self._json_response({"status": "started", "operation": "file-read", "target": target, "path": path_f})
            else:
                self._json_response({"error": "target and path required"}, 400)
        elif path == "/api/file-write":
            target = data.get("target", "")
            path_f = data.get("path", "")
            content = data.get("content", "")
            if target and path_f:
                threading.Thread(target=self._run_file_write, args=(target, path_f, content), daemon=True).start()
                self._json_response({"status": "started", "operation": "file-write", "target": target, "path": path_f})
            else:
                self._json_response({"error": "target and path required"}, 400)
        elif path == "/api/os-cmd":
            target = data.get("target", "")
            cmd = data.get("cmd", "")
            if target and cmd:
                threading.Thread(target=self._run_os_cmd, args=(target, cmd), daemon=True).start()
                self._json_response({"status": "started", "operation": "os-cmd", "target": target, "cmd": cmd})
            else:
                self._json_response({"error": "target and cmd required"}, 400)
        elif path == "/api/nosql":
            target = data.get("target", "")
            if target:
                threading.Thread(target=self._run_nosql, args=(target,), daemon=True).start()
                self._json_response({"status": "started", "operation": "nosql", "target": target})
            else:
                self._json_response({"error": "target required"}, 400)
        elif path == "/api/graphql":
            target = data.get("target", "")
            if target:
                threading.Thread(target=self._run_graphql, args=(target,), daemon=True).start()
                self._json_response({"status": "started", "operation": "graphql", "target": target})
            else:
                self._json_response({"error": "target required"}, 400)
        elif path == "/api/privesc":
            target = data.get("target", "")
            if target:
                threading.Thread(target=self._run_privesc, args=(target,), daemon=True).start()
                self._json_response({"status": "started", "operation": "privesc", "target": target})
            else:
                self._json_response({"error": "target required"}, 400)
        elif path == "/api/oob":
            target = data.get("target", "")
            host = data.get("host", "")
            channel = data.get("channel", "dns")
            if target and host:
                threading.Thread(target=self._run_oob, args=(target, host, channel), daemon=True).start()
                self._json_response({"status": "started", "operation": "oob", "target": target, "host": host, "channel": channel})
            else:
                self._json_response({"error": "target and host required"}, 400)
        elif path == "/api/report":
            target = data.get("target", "")
            if target:
                threading.Thread(target=self._run_report, args=(target,), daemon=True).start()
                self._json_response({"status": "started", "operation": "report", "target": target})
            else:
                self._json_response({"error": "target required"}, 400)
        elif path == "/api/cms":
            target = data.get("target", "")
            if target:
                threading.Thread(target=self._run_cms, args=(target,), daemon=True).start()
                self._json_response({"status": "started", "operation": "cms", "target": target})
            else:
                self._json_response({"error": "target required"}, 400)
        elif path == "/api/second-order":
            target = data.get("target", "")
            if target:
                threading.Thread(target=self._run_second_order, args=(target,), daemon=True).start()
                self._json_response({"status": "started", "operation": "second-order", "target": target})
            else:
                self._json_response({"error": "target required"}, 400)
        elif path == "/api/websocket":
            target = data.get("target", "")
            if target:
                threading.Thread(target=self._run_websocket, args=(target,), daemon=True).start()
                self._json_response({"status": "started", "operation": "websocket", "target": target})
            else:
                self._json_response({"error": "target required"}, 400)
        elif path == "/api/plugins":
            threading.Thread(target=self._run_plugins_api, daemon=True).start()
            self._json_response({"status": "started", "operation": "plugins"})
        else:
            self._json_response({"error": "not found"}, 404)

    def do_OPTIONS(self):
        self.send_response(200)
        self.send_header("Access-Control-Allow-Origin", "*")
        self.send_header("Access-Control-Allow-Methods", "GET, POST, OPTIONS")
        self.send_header("Access-Control-Allow-Headers", "Content-Type")
        self.end_headers()

    def _quick_detect(self, target: str):
        from injecta.core.engine import ScanEngine
        engine = ScanEngine(self.config_ref, self.logger_ref)
        if not engine.detector.fetch_baseline(target):
            return None, "unreachable"
        params = engine.detector.find_injection_points(target)
        for p in params:
            for t in "EBU":
                r = engine.detector.test_parameter(target, p, t)
                if r:
                    engine.vulnerable_params.append(r)
                    engine.injection_info = r
                    break
            if engine.injection_info:
                break
        if not engine.injection_info:
            return None, "not vulnerable"
        engine.dbms = engine._fingerprint_dbms(target)
        from injecta.payloads.mysql import MySQLPayloads
        from injecta.payloads.postgresql import PostgreSQLPayloads
        from injecta.payloads.mssql import MSSQLPayloads
        from injecta.payloads.oracle import OraclePayloads
        from injecta.payloads.sqlite import SQLitePayloads
        registry = {"mysql": MySQLPayloads, "postgresql": PostgreSQLPayloads,
                    "mssql": MSSQLPayloads, "oracle": OraclePayloads, "sqlite": SQLitePayloads}
        engine.payloads = registry.get(engine.dbms)
        return engine, None

    def _run_scan(self, target: str):
        self.__class__.scan_status = "running"
        self.__class__.scan_results = {"target": target, "vulnerable": False, "params": []}
        from injecta.core.engine import ScanEngine
        engine = ScanEngine(self.config_ref, self.logger_ref)
        try:
            engine.run(target)
            if engine.vulnerable_params:
                self.__class__.scan_results["vulnerable"] = True
                self.__class__.scan_results["params"] = [
                    {"param": v.get("param", ""), "technique": v.get("technique", ""),
                     "confidence": v.get("confidence", 0)} for v in engine.vulnerable_params
                ]
                self.__class__.scan_results["dbms"] = engine.dbms or "unknown"
                self.__class__.scan_results["waf"] = engine.waf.detected_wafs if engine.waf else []
            self.__class__.scan_status = "complete"
        except Exception as e:
            self.__class__.scan_results["error"] = str(e)
            self.__class__.scan_status = "error"
        self.__class__.scan_history.append({
            "timestamp": time.strftime("%Y-%m-%d %H:%M:%S"),
            "target": target,
            "status": self.__class__.scan_status,
        })

    def _run_file_read(self, target: str, path: str):
        self.__class__.scan_status = "running"
        self.__class__.scan_results = {"target": target, "operation": "file-read", "path": path}
        from injecta.enum.fileio import FileIO
        engine, err = self._quick_detect(target)
        if err:
            self.__class__.scan_results["error"] = err
            self.__class__.scan_status = "error"
            return
        try:
            io = FileIO(engine.req, self.config_ref, self.logger_ref, engine.payloads, engine.injection_info)
            results = io.read_file(target, engine.injection_info.get("param", ""), path)
            self.__class__.scan_results["results"] = results
            self.__class__.scan_results["file_content"] = "\n".join(results) if results else ""
            self.__class__.scan_status = "complete"
        except Exception as e:
            self.__class__.scan_results["error"] = str(e)
            self.__class__.scan_status = "error"

    def _run_file_write(self, target: str, path: str, content: str):
        self.__class__.scan_status = "running"
        self.__class__.scan_results = {"target": target, "operation": "file-write", "path": path}
        from injecta.enum.fileio import FileIO
        engine, err = self._quick_detect(target)
        if err:
            self.__class__.scan_results["error"] = err
            self.__class__.scan_status = "error"
            return
        try:
            io = FileIO(engine.req, self.config_ref, self.logger_ref, engine.payloads, engine.injection_info)
            ok = io.write_file(target, engine.injection_info.get("param", ""), path, content)
            self.__class__.scan_results["success"] = ok
            self.__class__.scan_status = "complete"
        except Exception as e:
            self.__class__.scan_results["error"] = str(e)
            self.__class__.scan_status = "error"

    def _run_os_cmd(self, target: str, cmd: str):
        self.__class__.scan_status = "running"
        self.__class__.scan_results = {"target": target, "operation": "os-cmd", "cmd": cmd}
        from injecta.enum.fileio import FileIO
        engine, err = self._quick_detect(target)
        if err:
            self.__class__.scan_results["error"] = err
            self.__class__.scan_status = "error"
            return
        try:
            io = FileIO(engine.req, self.config_ref, self.logger_ref, engine.payloads, engine.injection_info)
            results = io.os_cmd(target, engine.injection_info.get("param", ""), cmd)
            self.__class__.scan_results["results"] = results
            self.__class__.scan_results["output"] = "\n".join(results) if results else ""
            self.__class__.scan_status = "complete"
        except Exception as e:
            self.__class__.scan_results["error"] = str(e)
            self.__class__.scan_status = "error"

    def _run_nosql(self, target: str):
        self.__class__.scan_status = "running"
        self.__class__.scan_results = {"target": target, "operation": "nosql"}
        from injecta.techniques.nosql import NoSQLDetector
        from injecta.core.requester import VoidRequester
        req = VoidRequester(self.config_ref)
        detector = NoSQLDetector(req, self.config_ref, self.logger_ref)
        try:
            result = detector.scan(target)
            self.__class__.scan_results["nosql"] = result
            self.__class__.scan_status = "complete"
        except Exception as e:
            self.__class__.scan_results["error"] = str(e)
            self.__class__.scan_status = "error"

    def _run_graphql(self, target: str):
        self.__class__.scan_status = "running"
        self.__class__.scan_results = {"target": target, "operation": "graphql"}
        from injecta.techniques.graphql import GraphQLInjector
        from injecta.core.requester import VoidRequester
        req = VoidRequester(self.config_ref)
        injector = GraphQLInjector(req, self.config_ref, self.logger_ref)
        try:
            result = injector.discover(target)
            if result.get("found"):
                for ep in result.get("endpoints", []):
                    inj = injector.test_injection(ep)
                    result["injection"] = inj
            self.__class__.scan_results["graphql"] = result
            self.__class__.scan_status = "complete"
        except Exception as e:
            self.__class__.scan_results["error"] = str(e)
            self.__class__.scan_status = "error"

    def _run_privesc(self, target: str):
        self.__class__.scan_status = "running"
        self.__class__.scan_results = {"target": target, "operation": "privesc"}
        engine, err = self._quick_detect(target)
        if err:
            self.__class__.scan_results["error"] = err
            self.__class__.scan_status = "error"
            return
        try:
            from injecta.enum.privesc import PrivilegeEscalation
            pe = PrivilegeEscalation(engine.req, self.config_ref, self.logger_ref, engine.payloads, engine.injection_info or {})
            result = pe.enumerate_privileges(target, engine.injection_info.get("param", ""))
            if not result.get("is_admin"):
                esc = pe.attempt_escalation(target, engine.injection_info.get("param", ""))
                result["escalation"] = esc
            self.__class__.scan_results["privesc"] = result
            self.__class__.scan_status = "complete"
        except Exception as e:
            self.__class__.scan_results["error"] = str(e)
            self.__class__.scan_status = "error"

    def _run_oob(self, target: str, oob_host: str, channel: str = "dns"):
        self.__class__.scan_status = "running"
        self.__class__.scan_results = {"target": target, "operation": "oob", "host": oob_host, "channel": channel}
        engine, err = self._quick_detect(target)
        if err:
            self.__class__.scan_results["error"] = err
            self.__class__.scan_status = "error"
            return
        try:
            from injecta.enum.oob import OOBExfiltrator
            oob = OOBExfiltrator(engine.req, self.config_ref, self.logger_ref, engine.payloads, engine.injection_info or {})
            r = oob.exfiltrate(target, engine.injection_info.get("param", ""), "SELECT 1", oob_host, channel)
            self.__class__.scan_results["oob"] = r
            self.__class__.scan_status = "complete"
        except Exception as e:
            self.__class__.scan_results["error"] = str(e)
            self.__class__.scan_status = "error"

    def _run_report(self, target: str):
        self.__class__.scan_status = "running"
        self.__class__.scan_results = {"target": target, "operation": "report"}
        try:
            from injecta.core.engine import ScanEngine
            from injecta.enum.report import ReportGenerator
            existing = self.__class__.scan_results
            if existing.get("vulnerable") and existing.get("target") == target:
                data = {
                    "target": target,
                    "dbms": existing.get("dbms", "unknown"),
                    "waf": existing.get("waf", []),
                    "params": existing.get("params", []),
                    "timestamp": __import__("time").strftime("%Y-%m-%d %H:%M:%S"),
                    "tool": "Injecta Intelligence Platform",
                    "team": "Kael / Krynn Team",
                }
            else:
                engine = ScanEngine(self.config_ref, self.logger_ref)
                engine.run(target)
                data = {
                    "target": target,
                    "dbms": engine.dbms or "unknown",
                    "waf": engine.waf.detected_wafs if engine.waf else [],
                    "params": engine.vulnerable_params,
                    "timestamp": __import__("time").strftime("%Y-%m-%d %H:%M:%S"),
                    "tool": "Injecta Intelligence Platform",
                    "team": "Kael / Krynn Team",
                }
            rg = ReportGenerator(self.config_ref, self.logger_ref)
            paths = rg.generate_all(data)
            self.__class__.scan_results["report"] = paths
            self.__class__.scan_status = "complete"
        except Exception as e:
            self.__class__.scan_results["error"] = str(e)
            self.__class__.scan_status = "error"

    def _run_cms(self, target: str):
        self.__class__.scan_status = "running"
        self.__class__.scan_results = {"target": target, "operation": "cms"}
        from injecta.enum.cms import CMSFingerprinter
        from injecta.core.requester import VoidRequester
        try:
            req = VoidRequester(self.config_ref)
            cms = CMSFingerprinter(req, self.config_ref, self.logger_ref)
            result = cms.scan(target)
            self.__class__.scan_results["cms"] = result
            self.__class__.scan_status = "complete"
        except Exception as e:
            self.__class__.scan_results["error"] = str(e)
